from enum import Enum from dataclasses import dataclass from typing import Optional import json
class MessageType(str, Enum): PING = "ping" PONG = "pong" SUBSCRIBE = "subscribe" UNSUBSCRIBE = "unsubscribe" MESSAGE = "message" ERROR = "error" ACK = "ack"
@dataclass class WSMessage: type: MessageType channel: Optional[str] = None data: Optional[dict] = None id: Optional[str] = None
def to_json(self) -> str: return json.dumps({k: v for k, v in self.__dict__.items() if v is not None})
